import { useState } from 'react';
import '../styles/CreateDestination.css';

export default function CreateDestination({ onClose, onCreate }) {
    const [name, setName] = useState('');
    const [image, setImage] = useState('');
    const [price, setPrice] = useState('');
    const [startDate, setStartDate] = useState('');
    const [endDate, setEndDate] = useState('');
    const [creator, setCreator] = useState('');

    const handleSubmit = (e) => {
        e.preventDefault();

        const newDestination = {
            id: Date.now(), // Génère un ID unique
            name,
            image,
            price,
            startDate,
            endDate,
            creator,
            comments: [],
        };

        // 1. Récupère les anciennes destinations
        const stored = localStorage.getItem('destinations');
        const destinations = stored ? JSON.parse(stored) : [];

        // 2. Ajoute la nouvelle
        const updated = [...destinations, newDestination];
        localStorage.setItem('destinations', JSON.stringify(updated));

        // 3. Notifie le parent
        onCreate(newDestination);

        // 4. Ferme la modal
        onClose();
    };

    return (
        <form className="form-container" onSubmit={handleSubmit}>
            <h2>Nouvelle destination</h2>

            <input
                type="text"
                placeholder="Nom"
                value={name}
                onChange={(e) => setName(e.target.value)}
                required
            />
            <input
                type="text"
                placeholder="Image (URL)"
                value={image}
                onChange={(e) => setImage(e.target.value)}
            />
            <input
                type="number"
                placeholder="Prix"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                required
            />
            <input
                type="date"
                placeholder="Date de début"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                required
            />
            <input
                type="date"
                placeholder="Date de fin"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                required
            />
            <input
                type="text"
                placeholder="Créateur"
                value={creator}
                onChange={(e) => setCreator(e.target.value)}
                required
            />

            <button type="submit">Créer</button>
        </form>
    );
}
